void WndInit(IntPtr hwnd, MeowWindow me)
{
    RECT rcWork;
    SystemParametersInfo(SPI_GETWORKAREA, 0, ref rcWork, FALSE);

    SetWindowPos(hwnd, HWND_TOPMOST,
        rcWork.right - 136, rcWork.bottom - 40, 130, 34,
        SWP_NOACTIVATE);

    MEOW_WINDOW_FLOWBUTTON mwfb = new MEOW_WINDOW_FLOWBUTTON();
    ZeroMemory(mwfb, sizeof(MEOW_WINDOW_FLOWBUTTON));
    mwfb.parent = me;
    mwfb.memu = IntPtr.Zero;
    mwfb.tooltip = "“;
    buttons.Add(mwfb);
    mwfb.mode = 1;
    mwfb.memu = (IntPtr)1;
    buttons.Add(mwfb);
    mwfb.memu = (IntPtr)2;
    buttons.Add(mwfb);
    mwfb.memu = (IntPtr)3;
    buttons.Add(mwfb);
    uint count = buttons.Count;
    uint size = 28;
    SetWindowPos(hwnd, IntPtr.Zero, 0, 0, size * count + 2, size + 2, SWP_NOMOVE | SWP_NOACTIVATE);

    for (uint i = 0; i < count; i++)
    {
        IntPtr hWnd = CreateWindow("BUTTON", mwfb.tooltip, WS_VISIBLE | WS_CHILD | BS_OWNERDRAW, size * i + 1, 1, size, size, hwnd, buttons[i].memu, IntPtr.Zero, IntPtr.Zero);
        SetWindowSubclass(hWnd, MeowWindow.FlowButtonProc, IntPtr.Zero, (UIntPtr)GCHandle.ToIntPtr(GCHandle.Alloc(buttons[i])));
    }
}

以下C++代码用C#改写应该是怎么样的？
LRESULT CALLBACK MeowWindow::FlowButtonProc(HWND hWnd, UINT uMsg, WPARAM wParam, LPARAM lParam, UINT_PTR uIdSubclass, DWORD_PTR dwRefData)
{
	MEOW_WINDOW_FLOWBUTTON * mwfb = (MEOW_WINDOW_FLOWBUTTON *)(dwRefData);
	switch (uMsg)
	{
	case WM_LBUTTONDOWN:
		SendMessage(mwfb->parent->hwnd, WM_LBUTTONDOWN, wParam, lParam);
		break;
	case WM_MOUSEMOVE:
		SendMessage(mwfb->parent->hwnd, WM_MOUSEMOVE, wParam, lParam);
		if (!mwfb->mousetracking) {
			mwfb->mousetracking = true;
			TRACKMOUSEEVENT tme;
			tme.cbSize = sizeof(TRACKMOUSEEVENT);
			tme.dwFlags = TME_LEAVE;
			tme.hwndTrack = hWnd;
			TrackMouseEvent(&tme);
			SendMessage(hWnd, WM_SETFOCUS, NULL, NULL);
		}
		break;
	case WM_LBUTTONDBLCLK:
		SendMessage(hWnd, WM_LBUTTONDOWN, wParam, lParam);
		break;
	case WM_MOUSELEAVE:
		mwfb->mousetracking = false;
		SendMessage(hWnd, WM_KILLFOCUS, NULL, NULL);
		break;
	case WM_LBUTTONUP:
		SendMessage(mwfb->parent->hwnd, WM_LBUTTONUP, wParam, lParam);
		break;
	case WM_ERASEBKGND:
		return TRUE;
	}
	return DefSubclassProc(hWnd, uMsg, wParam, lParam);
}

private static IntPtr FlowButtonProc(IntPtr hWnd, uint uMsg, IntPtr wParam, IntPtr lParam, UIntPtr uIdSubclass, IntPtr dwRefData)
{
    MEOW_WINDOW_FLOWBUTTON mwfb = (MEOW_WINDOW_FLOWBUTTON)GCHandle.FromIntPtr(dwRefData).Target;
    switch (uMsg)
    {
        case WM_LBUTTONDOWN:
            SendMessage(mwfb.parent.hwnd, WM_LBUTTONDOWN, wParam, lParam);
            break;
        case WM_MOUSEMOVE:
            SendMessage(mwfb.parent.hwnd, WM_MOUSEMOVE, wParam, lParam);
            if (!mwfb.mousetracking)
            {
                mwfb.mousetracking = true;
                TRACKMOUSEEVENT tme = new TRACKMOUSEEVENT();
                tme.cbSize = (uint)Marshal.SizeOf(typeof(TRACKMOUSEEVENT));
                tme.dwFlags = TME_LEAVE;
                tme.hwndTrack = hWnd;
                TrackMouseEvent(ref tme);
                SendMessage(hWnd, WM_SETFOCUS, IntPtr.Zero, IntPtr.Zero);
            }
            break;
        case WM_LBUTTONDBLCLK:
            SendMessage(hWnd, WM_LBUTTONDOWN, wParam, lParam);
            break;
        case WM_MOUSELEAVE:
            mwfb.mousetracking = false;
            SendMessage(hWnd, WM_KILLFOCUS, IntPtr.Zero, IntPtr.Zero);
            break;
        case WM_LBUTTONUP:
            SendMessage(mwfb.parent.hwnd, WM_LBUTTONUP, wParam, lParam);
            break;
        case WM_ERASEBKGND:
            return (IntPtr)1;
    }
    return DefSubclassProc(hWnd, uMsg, wParam, lParam);
}

在C#中，tagTRACKMOUSEEVENT可以使用如下声明：

```csharp
[StructLayout(LayoutKind.Sequential)]
public struct TRACKMOUSEEVENT
{
    public uint cbSize;
    public uint dwFlags;
    public IntPtr hwndTrack;
    public uint dwHoverTime;
}
``` 

其中，`cbSize`表示结构体大小，需要在初始化结构体时进行设置。`dwFlags`是标志参数，与Win32 API中的`TrackMouseEvent`函数中的参数相对应。`hwndTrack`表示要跟踪鼠标事件的窗口句柄，`dwHoverTime`表示在鼠标指针进入客户区后，经过多少毫秒后将引发`WM_MOUSEHOVER`事件。
